    12→// WorkerState tracks the state of a Julia worker
    13→type WorkerState struct {
    14→	ID        int
    15→	PID       int
    16→	SHM       *shm.SharedMemManager
    17→	state     atomic.Value // string: IDLE, BUSY, ERROR
    18→	lastSeen  int64        // atomic: Unix nano
    19→	processed uint64       // atomic: count
    20→}
    21→
    22→// IsIdle checks if worker is ready to accept jobs
    23→func (w *WorkerState) IsIdle() bool {
    24→	s := w.state.Load()
    25→	if s == nil {
    26→		return true
    27→	}
    28→	return s.(string) == "IDLE"
    29→}
    30→
    31→// SetState updates worker state atomically
    32→func (w *WorkerState) SetState(s string) {
    33→	w.state.Store(s)
    34→}
    35→
    36→// UpdateLastSeen updates the last activity timestamp
    37→func (w *WorkerState) UpdateLastSeen() {
    38→	atomic.StoreInt64(&w.lastSeen, time.Now().UnixNano())
    39→}
    40→
    41→// GetLastSeen gets the last activity timestamp
    42→func (w *WorkerState) GetLastSeen() time.Time {
    43→	nano := atomic.LoadInt64(&w.lastSeen)
    44→	return time.Unix(0, nano)
    45→}
    46→
    47→// IncrementProcessed increments the job counter
    48→func (w *WorkerState) IncrementProcessed() uint64 {
    49→	return atomic.AddUint64(&w.processed, 1)
    50→}
    51→
    52→// Dispatcher: 메인 오케스트레이터
    53→// 데이터를 받아 가용한 워커에게 라운드-로빈으로 배분
    54→type Dispatcher struct {
    55→	workers       []*WorkerState
    56→	ringBuffer    *RingBuffer
    57→	roundRobin    uint64 // atomic: 다음 워커 인덱스
    58→	jobIDCounter  uint64 // atomic: 작업 ID
    59→	totalReceived uint64 // atomic: 수신한 작업 수
    60→	totalDropped  uint64 // atomic: 버린 작업 수
    61→
    62→	// Backpressure
    63→	backpressure atomic.Value // bool
    64→	maxQueueLen  int
    65→}
    66→
    67→// NewDispatcher creates a new dispatcher with N workers
    68→func NewDispatcher(workerCount int, ringBufferCapacity uint64) (*Dispatcher, error) {
    69→	rb, err := NewRingBuffer(ringBufferCapacity)
    70→	if err != nil {
    71→		return nil, fmt.Errorf("failed to create ring buffer: %w", err)
    72→	}
    73→
    74→	workers := make([]*WorkerState, workerCount)
    75→	for i := 0; i < workerCount; i++ {
    76→		workers[i] = &WorkerState{
    77→			ID: i,
    78→		}
    79→		workers[i].SetState("IDLE")
    80→	}
    81→
    82→	d := &Dispatcher{
    83→		workers:      workers,
    84→		ringBuffer:   rb,
    85→		roundRobin:   0,
    86→		jobIDCounter: 0,
    87→		maxQueueLen:  int(float64(ringBufferCapacity) * 0.8), // 80% of capacity
    88→	}
    89→
    90→	d.backpressure.Store(false)
    91→
    92→	return d, nil
    93→}
    94→
    95→// Submit submits a new job to the dispatcher
    96→// Returns job ID if successful, -1 if dropped due to backpressure
    97→func (d *Dispatcher) Submit(payload []byte, priority int) (uint64, error) {
    98→	// Check backpressure
    99→	if d.IsBackpressured() {
   100→		atomic.AddUint64(&d.totalDropped, 1)
   101→		return ^uint64(0), fmt.Errorf("backpressure active - job dropped")
   102→	}
   103→
   104→	// Create job
   105→	jobID := atomic.AddUint64(&d.jobIDCounter, 1)
   106→	job := Job{
   107→		ID:       jobID,
   108→		Priority: priority,
   109→		Payload:  payload,
   110→		Response: make(chan []byte, 1), // Buffered to avoid blocking
   111→	}
   112→
   113→	// Try to publish to ring buffer
   114→	if !d.ringBuffer.Publish(job) {
   115→		atomic.AddUint64(&d.totalDropped, 1)
   116→		return ^uint64(0), fmt.Errorf("ring buffer full - job dropped")
   117→	}
   118→
   119→	atomic.AddUint64(&d.totalReceived, 1)
   120→
   121→	// Update backpressure flag
   122→	queueSize := d.ringBuffer.Size()
   123→	if queueSize > uint64(d.maxQueueLen) {
   124→		d.backpressure.Store(true)
   125→	}
   126→
   127→	return jobID, nil
   128→}
   129→
   130→// Run starts the dispatcher (runs until context is cancelled)
   131→// This distributes jobs from ring buffer to workers
   132→func (d *Dispatcher) Run(ctx context.Context) error {
   133→	for {
   134→		select {
   135→		case <-ctx.Done():
   136→			return ctx.Err()
   137→
   138→		default:
   139→			// Try to distribute jobs
   140→			job, ok := d.ringBuffer.Subscribe()
   141→			if !ok {
   142→				// No jobs available, sleep briefly
   143→				time.Sleep(100 * time.Microsecond)
   144→				continue
   145→			}
   146→
   147→			// Find next available worker (round-robin)
   148→			workerIdx := d.findNextWorker()
   149→			if workerIdx < 0 {
   150→				// All workers busy, push back to ring buffer? (advanced feature)
   151→				continue
   152→			}
   153→
   154→			// Assign job to worker
   155→			worker := d.workers[workerIdx]
   156→			worker.SetState("BUSY")
   157→			worker.UpdateLastSeen()
   158→
   159→			// Send to worker via channel (non-blocking)
   160→			go d.assignJobToWorker(ctx, worker, job)
   161→
   162→			// Update backpressure
   163→			if d.ringBuffer.Size() < uint64(d.maxQueueLen) {
   164→				d.backpressure.Store(false)
   165→			}
   166→		}
   167→	}
   168→}
   169→
   170→// findNextWorker finds the next idle worker using round-robin
   171→// Returns -1 if no idle worker found
   172→func (d *Dispatcher) findNextWorker() int {
   173→	start := atomic.AddUint64(&d.roundRobin, 1)
   174→	workerCount := uint64(len(d.workers))
   175→
   176→	for i := uint64(0); i < workerCount; i++ {
   177→		idx := (start + i) % workerCount
   178→		if d.workers[idx].IsIdle() {
   179→			return int(idx)
   180→		}
   181→	}
   182→
   183→	return -1 // All workers busy
   184→}
   185→
   186→// assignJobToWorker assigns a job to a specific worker
   187→// This runs in a separate goroutine to avoid blocking the dispatcher
   188→func (d *Dispatcher) assignJobToWorker(ctx context.Context, worker *WorkerState, job *Job) {
   189→	// TODO: In real implementation, communicate with Julia via shared memory
   190→	// For now, simulate processing
   191→	defer func() {
   192→		worker.SetState("IDLE")
   193→		worker.IncrementProcessed()
   194→	}()
   195→
   196→	// Simulate work
   197→	time.Sleep(10 * time.Millisecond)
   198→
   199→	// Send dummy response
   200→	select {
   201→	case job.Response <- []byte("processed"):
   202→	case <-ctx.Done():
   203→	}
   204→}
   205→
   206→// IsBackpressured checks if backpressure is active
   207→func (d *Dispatcher) IsBackpressured() bool {
   208→	val := d.backpressure.Load()
   209→	if val == nil {
   210→		return false
   211→	}
   212→	if b, ok := val.(bool); ok {
   213→		return b
   214→	}
   215→	return false
   216→}
   217→
   218→// Stats returns dispatcher statistics
   219→func (d *Dispatcher) Stats() map[string]interface{} {
   220→	idleCount := 0
   221→	busyCount := 0
   222→	for _, w := range d.workers {
   223→		if w.IsIdle() {
   224→			idleCount++
   225→		} else {
   226→			busyCount++
   227→		}
   228→	}
   229→
   230→	return map[string]interface{}{
   231→		"total_workers":   len(d.workers),
   232→		"idle_workers":    idleCount,
   233→		"busy_workers":    busyCount,
   234→		"queue_size":      d.ringBuffer.Size(),
   235→		"queue_capacity":  d.ringBuffer.Capacity(),
   236→		"total_received":  atomic.LoadUint64(&d.totalReceived),
   237→		"total_dropped":   atomic.LoadUint64(&d.totalDropped),
   238→		"backpressured":   d.IsBackpressured(),
   239→		"round_robin":     atomic.LoadUint64(&d.roundRobin),
   240→	}
   241→}
   242→
   243→// Close gracefully shuts down the dispatcher
   244→func (d *Dispatcher) Close() error {
   245→	// Wait for workers to finish
   246→	for _, w := range d.workers {
   247→		w.SetState("SHUTDOWN")
   248→	}
   249→	return nil
   250→}
