     1→package dispatcher
     2→
     3→import (
     4→	"context"
     5→	"fmt"
     6→	"os/exec"
     7→	"runtime"
     8→	"sync"
     9→	"sync/atomic"
    10→	"time"
    11→
    12→	"grie-engine/internal/shm"
    13→)
    14→
    15→// Worker represents a single Julia worker goroutine
    16→type Worker struct {
    17→	ID            int
    18→	WorkerState   *WorkerState
    19→	juliaProcess  *exec.Cmd
    20→	shmPath       string
    21→	processedJobs uint64 // atomic
    22→	errors        uint64 // atomic
    23→	lastError     atomic.Value // error
    24→	cpuCore       int // CPU core to pin to (0 = no pinning)
    25→}
    26→
    27→// NewWorker creates a new worker for a Julia instance
    28→func NewWorker(id int, workerState *WorkerState, cpuCore int) *Worker {
    29→	w := &Worker{
    30→		ID:          id,
    31→		WorkerState: workerState,
    32→		cpuCore:     cpuCore,
    33→	}
    34→	return w
    35→}
    36→
    37→// Start initializes the shared memory and launches the Julia process
    38→func (w *Worker) Start(ctx context.Context) error {
    39→	// Create shared memory for this worker
    40→	shmMgr, err := shm.Create(10 * 1024 * 1024) // 10MB per worker
    41→	if err != nil {
    42→		return fmt.Errorf("failed to create shared memory: %w", err)
    43→	}
    44→
    45→	w.WorkerState.SHM = shmMgr
    46→	w.shmPath = shmMgr.Path()
    47→
    48→	// TODO: Launch Julia process
    49→	// juliaScript := fmt.Sprintf("julia_worker_%d.jl", w.ID)
    50→	// w.juliaProcess = exec.CommandContext(ctx, "julia", juliaScript, w.shmPath)
    51→
    52→	return nil
    53→}
    54→
    55→// Run executes the worker main loop (pinned to OS thread if cpuCore >= 0)
    56→func (w *Worker) Run(ctx context.Context, jobQueue chan *Job) error {
    57→	// Pin to OS thread if requested
    58→	if w.cpuCore >= 0 {
    59→		runtime.LockOSThread()
    60→		defer runtime.UnlockOSThread()
    61→
    62→		// TODO: Actually pin to CPU core using taskset
    63→		// cmd := exec.Command("taskset", "-p", "-c", fmt.Sprintf("%d", w.cpuCore), fmt.Sprintf("%d", os.Getpid()))
    64→		// cmd.Run()
    65→	}
    66→
    67→	for {
    68→		select {
    69→		case job := <-jobQueue:
    70→			if job == nil {
    71→				// Channel closed
    72→				return nil
    73→			}
    74→
    75→			result, err := w.processJob(ctx, job)
    76→			if err != nil {
    77→				atomic.AddUint64(&w.errors, 1)
    78→				w.lastError.Store(err)
    79→				job.Response <- nil
    80→			} else {
    81→				job.Response <- result
    82→			}
    83→
    84→			w.WorkerState.IncrementProcessed()
    85→
    86→		case <-ctx.Done():
    87→			return ctx.Err()
    88→		}
    89→	}
    90→}
    91→
    92→// processJob sends job to Julia via shared memory and waits for result
    93→func (w *Worker) processJob(ctx context.Context, job *Job) ([]byte, error) {
    94→	if w.WorkerState.SHM == nil {
    95→		return nil, fmt.Errorf("shared memory not initialized")
    96→	}
    97→
    98→	// Write job payload to shared memory
    99→	if err := w.WorkerState.SHM.WriteData(job.Payload); err != nil {
   100→		return nil, fmt.Errorf("failed to write to shared memory: %w", err)
   101→	}
   102→
   103→	// Wait for Julia to process and respond
   104→	// Using polling with timeout
   105→	deadline := time.Now().Add(5 * time.Second)
   106→
   107→	for {
   108→		select {
   109→		case <-ctx.Done():
   110→			return nil, ctx.Err()
   111→
   112→		default:
   113→			if time.Now().After(deadline) {
   114→				return nil, fmt.Errorf("timeout waiting for Julia response")
   115→			}
   116→
   117→			// Try to read result
   118→			result, err := w.WorkerState.SHM.ReadData(100) // 100ms timeout per try
   119→			if err == nil {
   120→				return result, nil
   121→			}
   122→
   123→			// Not ready yet, keep polling
   124→			time.Sleep(10 * time.Millisecond)
   125→		}
   126→	}
   127→}
   128→
   129→// GetStats returns worker statistics
   130→func (w *Worker) GetStats() map[string]interface{} {
   131→	lastErr := w.lastError.Load()
   132→	errStr := ""
   133→	if lastErr != nil {
   134→		errStr = lastErr.(error).Error()
   135→	}
   136→
   137→	return map[string]interface{}{
   138→		"id":               w.ID,
   139→		"state":            w.WorkerState.state.Load(),
   140→		"processed_jobs":   atomic.LoadUint64(&w.processedJobs),
   141→		"errors":           atomic.LoadUint64(&w.errors),
   142→		"last_error":       errStr,
   143→		"last_seen":        w.WorkerState.GetLastSeen(),
   144→		"shm_path":         w.shmPath,
   145→		"cpu_core":         w.cpuCore,
   146→	}
   147→}
   148→
   149→// Close cleans up the worker
   150→func (w *Worker) Close() error {
   151→	if w.WorkerState.SHM != nil {
   152→		if err := w.WorkerState.SHM.Close(); err != nil {
   153→			return fmt.Errorf("failed to close shared memory: %w", err)
   154→		}
   155→	}
   156→
   157→	if w.juliaProcess != nil {
   158→		if err := w.juliaProcess.Process.Kill(); err != nil {
   159→			return fmt.Errorf("failed to kill Julia process: %w", err)
   160→		}
   161→	}
   162→
   163→	return nil
   164→}
