    82→func TestDispatcher_Backpressure(t *testing.T) {
    83→	d, err := NewDispatcher(2, 16) // Small buffer (power of 2) to trigger backpressure
    84→	if err != nil {
    85→		t.Fatalf("NewDispatcher failed: %v", err)
    86→	}
    87→
    88→	// maxQueueLen = 16 * 0.8 = 12.8 ≈ 12
    89→	// Backpressure activates when queueSize > 12 (i.e., at 13+)
    90→	// Submit first 13 successfully (queue size 13 triggers backpressure AFTER)
    91→	for i := 0; i < 13; i++ {
    92→		_, submitErr := d.Submit([]byte{byte(i)}, 5)
    93→		if submitErr != nil {
    94→			t.Fatalf("Submit %d should succeed, got: %v", i, submitErr)
    95→		}
    96→	}
    97→
    98→	// Queue should now be backpressured
    99→	if !d.IsBackpressured() {
   100→		t.Fatal("Should be backpressured after 13 submissions (> 12.8 threshold)")
   101→	}
   102→
   103→	// 14th submission should fail due to backpressure check
   104→	_, submitErr := d.Submit([]byte("extra"), 5)
   105→	if submitErr == nil {
   106→		t.Fatal("Submit 14 should fail due to backpressure")
   107→	}
   108→
