### 3-3. `internal/retry/backoff.go`

```go
package retry

import (
    "context"
    "errors"
    "math/rand"
    "time"
)

// ErrorType classifies errors for retry decision
type ErrorType int

const (
    ErrorTransient  ErrorType = iota  // 재시도 가능 (네트워크, 일시적 SHM 잠금)
    ErrorPermanent                     // 재시도 불가 (데이터 손상, 잘못된 인수)
)

// RetryableError wraps an error with retry classification
type RetryableError struct {
    Err      error
    Type     ErrorType
}

func (e *RetryableError) Error() string { return e.Err.Error() }
func (e *RetryableError) Unwrap() error { return e.Err }

// IsPermanent returns true if the error should not be retried
func IsPermanent(err error) bool {
    var re *RetryableError
    if errors.As(err, &re) {
        return re.Type == ErrorPermanent
    }
    return false  // 기본값: transient (재시도)
}

// RetryConfig controls retry behavior
type RetryConfig struct {
    MaxAttempts  int
    BaseDelay    time.Duration  // 초기 대기 시간
    MaxDelay     time.Duration  // 최대 대기 시간 (cap)
    Multiplier   float64        // 백오프 배수 (예: 2.0)
    JitterFactor float64        // Jitter 비율 (예: 0.1 = ±10%)
}

// DefaultRetryConfig는 SHM 작업에 적합한 기본값
func DefaultRetryConfig() RetryConfig {
    return RetryConfig{
        MaxAttempts:  3,
        BaseDelay:    10 * time.Millisecond,
        MaxDelay:     1 * time.Second,
        Multiplier:   2.0,
        JitterFactor: 0.1,
    }
}

// Do executes fn with retry logic
// fn이 nil error를 반환하면 성공, PermanentError를 반환하면 즉시 중단
// context 취소 시 즉시 중단
func Do(ctx context.Context, cfg RetryConfig, fn func() error) error

// calculateDelay computes next backoff duration with jitter
func calculateDelay(attempt int, cfg RetryConfig) time.Duration {
    // delay = min(BaseDelay * Multiplier^attempt, MaxDelay)
    // jitter = delay * JitterFactor * random(-1, 1)
    // final = delay + jitter
}
```

에러 분류 규칙 (적용 위치: `worker.processJob()`):
- `"shared memory not initialized"` → `ErrorPermanent`
- `"data too large"` → `ErrorPermanent`
- `"timeout waiting for Julia response"` → `ErrorTransient`
- `"cannot acquire write lock"` → `ErrorTransient` (경쟁 조건)
- `"cannot acquire read lock"` → `ErrorTransient`

