package monitoring

import (
    "fmt"
    "io"
    "sync/atomic"
    "time"
)

// Counter는 단조 증가 카운터
type Counter struct {
    name  string
    help  string
    value uint64  // atomic
}

func (c *Counter) Inc() { atomic.AddUint64(&c.value, 1) }
func (c *Counter) Add(n uint64) { atomic.AddUint64(&c.value, n) }
func (c *Counter) Value() uint64 { return atomic.LoadUint64(&c.value) }

// Gauge는 상하 변동 가능한 값
type Gauge struct {
    name  string
    help  string
    value int64  // atomic (int64 for negative values)
}

func (g *Gauge) Set(v int64) { atomic.StoreInt64(&g.value, v) }
func (g *Gauge) Inc() { atomic.AddInt64(&g.value, 1) }
func (g *Gauge) Dec() { atomic.AddInt64(&g.value, -1) }
func (g *Gauge) Value() int64 { return atomic.LoadInt64(&g.value) }

// Registry는 모든 메트릭의 전역 레지스트리
type Registry struct {
    // Dispatcher 메트릭
    JobsReceived   *Counter
    JobsDropped    *Counter
    JobsProcessed  *Counter
    JobsFailed     *Counter
    QueueSize      *Gauge
    ActiveWorkers  *Gauge

    // Circuit Breaker 메트릭 (per-worker prefix)
    CBAllowed      *Counter
    CBRejected     *Counter
    CBStateChanges *Counter

    // Latency 메트릭
    LatencyTotalNs *Counter  // sum for avg calculation
    LatencyCount   *Counter

    // SHM 메트릭
    SHMWrites      *Counter
    SHMReads       *Counter
    SHMErrors      *Counter

    // Retry 메트릭
    RetryAttempts  *Counter
    RetrySuccess   *Counter
    RetryExhausted *Counter

    startTime time.Time
}

// Global registry (싱글톤, 표준 라이브러리만 사용)
