## 4. 수정된 worker.go 핵심 변경 부분

기존 코드:
```go
// internal/dispatcher/worker.go:105
deadline := time.Now().Add(5 * time.Second)  // 하드코딩
```

변경 후:
```go
// Worker 구조체에 추가
type Worker struct {
    // ... 기존 필드 ...
    timeoutCfg     *config.TimeoutConfig
    circuitBreaker *circuitbreaker.CircuitBreaker
    retryConfig    retry.RetryConfig
}

// processJob 변경
func (w *Worker) processJob(ctx context.Context, job *Job) ([]byte, error) {
    // 1. Circuit Breaker 체크
    if err := w.circuitBreaker.Allow(); err != nil {
        return nil, &retry.RetryableError{Err: err, Type: retry.ErrorPermanent}
    }

    var result []byte
    // 2. Retry 로직으로 감싸기
    err := retry.Do(ctx, w.retryConfig, func() error {
        if w.WorkerState.SHM == nil {
            return &retry.RetryableError{
                Err:  fmt.Errorf("shared memory not initialized"),
                Type: retry.ErrorPermanent,
            }
        }

        if err := w.WorkerState.SHM.WriteData(job.Payload); err != nil {
            return &retry.RetryableError{Err: err, Type: retry.ErrorTransient}
        }

        // 하드코딩 5초 → 설정값으로 교체
        deadline := time.Now().Add(w.timeoutCfg.JobProcessTimeout)
        // ... 나머지 로직 동일 ...
        return nil
    })

    // 3. Circuit Breaker 결과 기록
    if err != nil {
        w.circuitBreaker.RecordFailure()
        return nil, err
    }
    w.circuitBreaker.RecordSuccess()
    return result, nil
}
```

